import { useState, useEffect } from 'react';
import axios from 'axios';
import './ShopHome.css';

const API = 'http://localhost:5000/api';

function Stars({ rating }) {
  return (
    <div className="stars">
      {[1,2,3,4,5].map(s => (
        <span key={s} className={`star ${s <= rating ? '' : 'empty'}`}>★</span>
      ))}
    </div>
  );
}

export default function ShopHome() {
  const [tab, setTab] = useState('home');
  const [settings, setSettings] = useState({});
  const [products, setProducts] = useState([]);
  const [reviews, setReviews] = useState([]);
  const [reviewForm, setReviewForm] = useState({ customer_name: '', rating: 5, comment: '' });
  const [reviewMsg, setReviewMsg] = useState('');
  const [hoverRating, setHoverRating] = useState(0);

  useEffect(() => {
    axios.get(`${API}/settings`).then(r => setSettings(r.data));
    axios.get(`${API}/products`).then(r => setProducts(r.data));
    axios.get(`${API}/reviews`).then(r => setReviews(r.data));
  }, []);

  const avgRating = reviews.length ? (reviews.reduce((a,r) => a+r.rating, 0) / reviews.length).toFixed(1) : '0';

  const submitReview = async () => {
    if (!reviewForm.customer_name.trim()) { setReviewMsg('❌ பேரு சொல்லுங்க'); return; }
    await axios.post(`${API}/reviews`, reviewForm);
    setReviewMsg('✅ நன்றி! Review-ஐ Admin approve பண்ணிய பிறகு show ஆகும்');
    setReviewForm({ customer_name: '', rating: 5, comment: '' });
  };

  const hours = [
    { day: 'திங்கள்', time: '7:30 am – 9:30 pm' },
    { day: 'செவ்வாய்', time: '7:30 am – 9:30 pm' },
    { day: 'புதன்', time: '7:30 am – 9:30 pm' },
    { day: 'வியாழன்', time: '7:30 am – 9:30 pm' },
    { day: 'வெள்ளி', time: '7:30 am – 9:30 pm' },
    { day: 'சனி', time: '7:30 am – 7:30 pm' },
    { day: 'ஞாயிறு', time: '7:30 – 9:30 am' },
  ];

  return (
    <div className="shop-page">
      {/* Header */}
      <header className="shop-header">
        <div className="shop-header-inner">
          <div className="shop-logo">
            <span className="shop-icon">👗</span>
            <div>
              <h1>{settings.shop_name || 'அகத்தியர் Store'}</h1>
              <p>Dress Store</p>
            </div>
          </div>
          <nav className="shop-nav">
            {['home','products','reviews','about'].map(t => (
              <button key={t} className={`nav-btn ${tab === t ? 'active' : ''}`}
                onClick={() => setTab(t)}>
                {{ home: '🏠 Home', products: '👗 Products', reviews: '⭐ Reviews', about: 'ℹ️ About' }[t]}
              </button>
            ))}
          </nav>
        </div>
      </header>

      <main className="shop-main">
        {/* HOME TAB */}
        {tab === 'home' && (
          <div>
            <div className="hero-section">
              <div className="hero-content">
                <h2>உங்களை வரவேற்கிறோம்</h2>
                <p>சிறந்த தரமான dress-கள் சிறந்த விலையில்</p>
                <div className="hero-rating">
                  <Stars rating={Math.round(parseFloat(avgRating))} />
                  <span>{avgRating} / 5 ({reviews.length} Reviews)</span>
                </div>
                <div className="hero-btns">
                  <button className="btn btn-primary" onClick={() => setTab('products')}>👗 Products பாருங்க</button>
                  <button className="btn btn-secondary" onClick={() => setTab('reviews')}>⭐ Reviews பாருங்க</button>
                </div>
              </div>
              <div className="hero-image">🛍️</div>
            </div>

            <div className="info-cards">
              <div className="info-card">
                <span className="info-icon">📍</span>
                <h3>Address</h3>
                <p>{settings.shop_address || 'C.Ayyampalayam, Manachnallur, Tamil Nadu 621005'}</p>
              </div>
              <div className="info-card">
                <span className="info-icon">📞</span>
                <h3>Phone</h3>
                <p><a href={`tel:${settings.shop_phone}`}>{settings.shop_phone || '074483 67291'}</a></p>
              </div>
              <div className="info-card">
                <span className="info-icon">🕐</span>
                <h3>Today's Hours</h3>
                <p style={{color: '#10B981', fontWeight: 600}}>இப்போது Open ✓</p>
              </div>
            </div>
          </div>
        )}

        {/* PRODUCTS TAB */}
        {tab === 'products' && (
          <div>
            <h2 className="section-title">👗 எங்கள் Products</h2>
            {products.length === 0 ? (
              <div className="empty-state">Products விரைவில் வரும்...</div>
            ) : (
              <div className="products-grid">
                {products.map(p => (
                  <div key={p.id} className="product-card">
                    <div className="product-icon">👗</div>
                    <h3>{p.name}</h3>
                    {p.category && <span className="product-category">{p.category}</span>}
                    <div className="product-price">₹{p.price.toLocaleString()}</div>
                    <div className={`product-stock ${p.stock > 5 ? 'in-stock' : p.stock > 0 ? 'low-stock' : 'out-stock'}`}>
                      {p.stock > 5 ? '✅ Available' : p.stock > 0 ? `⚠️ Only ${p.stock} left` : '❌ Out of Stock'}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* REVIEWS TAB */}
        {tab === 'reviews' && (
          <div>
            <h2 className="section-title">⭐ Customer Reviews</h2>
            <div className="rating-summary">
              <div className="big-rating">{avgRating}</div>
              <Stars rating={Math.round(parseFloat(avgRating))} />
              <p>{reviews.length} reviews</p>
            </div>

            <div className="reviews-list">
              {reviews.map(r => (
                <div key={r.id} className="review-card">
                  <div className="review-header">
                    <div className="reviewer-avatar">{r.customer_name[0]}</div>
                    <div>
                      <strong>{r.customer_name}</strong>
                      <Stars rating={r.rating} />
                    </div>
                    <span className="review-date">{r.created_at}</span>
                  </div>
                  {r.comment && <p className="review-comment">{r.comment}</p>}
                </div>
              ))}
            </div>

            {/* Write Review Form */}
            <div className="review-form-card">
              <h3>📝 Review எழுதுங்க</h3>
              {reviewMsg && <div className="alert alert-success">{reviewMsg}</div>}
              <div className="form-group">
                <label>உங்கள் பேரு</label>
                <input className="form-control" placeholder="பேரு" value={reviewForm.customer_name}
                  onChange={e => setReviewForm({...reviewForm, customer_name: e.target.value})} />
              </div>
              <div className="form-group">
                <label>Rating</label>
                <div className="star-picker">
                  {[1,2,3,4,5].map(s => (
                    <span key={s}
                      className={`star-btn ${(hoverRating || reviewForm.rating) >= s ? 'active' : ''}`}
                      onMouseEnter={() => setHoverRating(s)}
                      onMouseLeave={() => setHoverRating(0)}
                      onClick={() => setReviewForm({...reviewForm, rating: s})}>★</span>
                  ))}
                </div>
              </div>
              <div className="form-group">
                <label>Comment (Optional)</label>
                <textarea className="form-control" rows={3} placeholder="உங்கள் experience சொல்லுங்க..."
                  value={reviewForm.comment}
                  onChange={e => setReviewForm({...reviewForm, comment: e.target.value})} />
              </div>
              <button className="btn btn-primary" onClick={submitReview}>⭐ Submit Review</button>
            </div>
          </div>
        )}

        {/* ABOUT TAB */}
        {tab === 'about' && (
          <div>
            <h2 className="section-title">ℹ️ About Us</h2>
            <div className="about-card">
              <h3>🏪 {settings.shop_name || 'அகத்தியர் Store'}</h3>
              <p>சிறந்த தரமான dress-கள் கிடைக்கும் எங்கள் shop-ல்.</p>
              <div className="hours-table">
                <h4>⏰ Working Hours</h4>
                {hours.map(h => (
                  <div key={h.day} className="hours-row">
                    <span>{h.day}</span><span>{h.time}</span>
                  </div>
                ))}
              </div>
              <div className="contact-section">
                <h4>📞 Contact</h4>
                <p>{settings.shop_phone}</p>
                <p>{settings.shop_address}</p>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="shop-footer">
        <p>© 2024 {settings.shop_name || 'அகத்தியர் Store'} · All Rights Reserved</p>
        <a href="/admin/login" className="admin-link">Admin Login</a>
      </footer>
    </div>
  );
}
